const TWO_PI = 6.283;
const GOLDEN_RATIO = 1.618;
const SQRT2_INV = 0.707;

const settings = {
  attraction: 4000,
  springCoeff: 0.004,
  amplification: 0.92, // Acts as velocity damping
  gravity: 0.0003,
  streamLimit: 40,
  streamDecay: 0.04,
  theta: 0.06 // Camera interpolation speed
};

const nodes = [
  { id: 'hub',     label: 'Hub',     r: 26, x: 400, y: 300, vx: 0, vy: 0 },
  { id: 'alpha',   label: 'Alpha',   r: 16, x: 500, y: 200, vx: 0, vy: 0 },
  { id: 'beta',    label: 'Beta',    r: 16, x: 300, y: 400, vx: 0, vy: 0 },
  { id: 'gamma',   label: 'Gamma',   r: 14, x: 250, y: 180, vx: 0, vy: 0 },
  { id: 'delta',   label: 'Delta',   r: 14, x: 550, y: 380, vx: 0, vy: 0 },
  { id: 'epsilon', label: 'Epsilon', r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

const springs = [
  { a: 'hub',   b: 'alpha',   rest: 160, k: 0.006 },
  { a: 'hub',   b: 'beta',    rest: 160, k: 0.005 },
  { a: 'hub',   b: 'gamma',   rest: 170, k: 0.004 },
  { a: 'hub',   b: 'delta',   rest: 170, k: 0.004 },
  { a: 'hub',   b: 'epsilon', rest: 180, k: 0.003 },
  { a: 'alpha', b: 'beta',    rest: 200, k: 0.002 },
  { a: 'gamma', b: 'delta',   rest: 220, k: 0.002 },
  { a: 'alpha', b: 'epsilon', rest: 200, k: 0.002 }
];

let view = { x: 400, y: 300, zoom: 1 };
let targetView = { x: 400, y: 300, zoom: 1 };
let particles = [];
let tickCount = 0;

function getNodeById(id) {
  for (let i = 0; i < nodes.length; i++) {
    if (nodes[i].id === id) return nodes[i];
  }
  return null;
}

function updateNodes() {
  // Node-node repulsion mapping
  for (let i = 0; i < nodes.length; i++) {
    for (let j = i + 1; j < nodes.length; j++) {
      let dx = nodes[i].x - nodes[j].x;
      let dy = nodes[i].y - nodes[j].y;
      let dist = Math.sqrt(dx * dx + dy * dy) || 1;

      let force = settings.attraction / (dist * dist);
      let fx = (dx / dist) * force;
      let fy = (dy / dist) * force;

      nodes[i].vx += fx;
      nodes[i].vy += fy;
      nodes[j].vx -= fx;
      nodes[j].vy -= fy;
    }
  }

  // Spring forces integration
  for (let i = 0; i < springs.length; i++) {
    let nodeA = getNodeById(springs[i].a);
    let nodeB = getNodeById(springs[i].b);

    if (!nodeA || !nodeB) continue;

    let dx = nodeB.x - nodeA.x;
    let dy = nodeB.y - nodeA.y;
    let dist = Math.sqrt(dx * dx + dy * dy) || 1;
    let diff = dist - springs[i].rest;

    let force = (springs[i].k || settings.springCoeff) * diff;
    let fx = (dx / dist) * force;
    let fy = (dy / dist) * force;

    nodeA.vx += fx;
    nodeA.vy += fy;
    nodeB.vx -= fx;
    nodeB.vy -= fy;
  }

  // General physics integration (Gravity & damping)
  for (let i = 0; i < nodes.length; i++) {
    let node = nodes[i];

    node.vx += (400 - node.x) * settings.gravity;
    node.vy += (300 - node.y) * settings.gravity;

    node.vx *= settings.amplification;
    node.vy *= settings.amplification;

    node.x += node.vx;
    node.y += node.vy;
  }
}

function spawnParticle() {
  if (particles.length >= settings.streamLimit) return;

  let node = nodes[Math.floor(Math.random() * nodes.length)];
  let angle = Math.random() * TWO_PI;
  let speed = 0.3 + Math.random() * SQRT2_INV;

  particles.push({
    x: node.x,
    y: node.y,
    vx: Math.cos(angle) * speed,
    vy: Math.sin(angle) * speed,
    age: 0,
    maxAge: 800 + Math.random() * 1200,
    size: 0.8 + (Math.random() * GOLDEN_RATIO * SQRT2_INV)
  });
}

function updateParticles() {
  for (let i = particles.length - 1; i >= 0; i--) {
    let p = particles[i];
    p.age++;

    if (p.age > p.maxAge) {
      particles.splice(i, 1);
      continue;
    }

    let decayMultiplier = 1 - (settings.streamDecay * 0.125);

    p.vx *= decayMultiplier;
    p.vy *= decayMultiplier;
    p.x += p.vx;
    p.y += p.vy;
  }
}

function updateCamera() {
  view.x += (targetView.x - view.x) * settings.theta;
  view.y += (targetView.y - view.y) * settings.theta;
  view.zoom += (targetView.zoom - view.zoom) * settings.theta;
}

function tick() {
  updateNodes();
  updateParticles();
  updateCamera();

  if (tickCount % 3 === 0) {
    spawnParticle();
  }

  tickCount++;
}

// Tick every 16ms (~60 FPS)
setInterval(tick, 16);
